	@Test
	void extractsRepeatedLeavesOncePerOccurrenceAndCanonicalizesEquivalentTrees() throws ReflectiveOperationException {
		StatementPattern a = pattern("urn:test:a");
		StatementPattern b = pattern("urn:test:b");
		Join original = new Join(a, new Join(a.clone(), b));
		Memo memo = memo();
		int rootGroupId = memo.intern(original);
		int aGroupId = memo.intern(a.clone());
		int bGroupId = memo.intern(b.clone());
		MemoExpr originalExpression = memo.group(rootGroupId).expressions().getFirst();

		Join equivalent = new Join(new Join(b.clone(), a.clone()), a.clone());
		MemoExpr equivalentExpression = memo.addLogicalAlternative(rootGroupId, equivalent).orElseThrow();

		Object originalRegion = extract(memo, rootGroupId, originalExpression);
		Object equivalentRegion = extract(memo, rootGroupId, equivalentExpression);

		assertTrue((boolean) invoke(originalRegion, "supported"));
		assertTrue((boolean) invoke(equivalentRegion, "supported"));
		JoinRegion region = (JoinRegion) invoke(originalRegion, "region");
		assertEquals(List.of(aGroupId, aGroupId, bGroupId),
				region.factors().stream().map(JoinFactor::groupId).toList(),
				"self-join occurrences must not collapse when their memo group is shared");
		assertEquals(List.of(0, 1, 2), region.factors().stream().map(JoinFactor::occurrenceId).toList());
		assertEquals(invoke(originalRegion, "fingerprint"), invoke(equivalentRegion, "fingerprint"),
				"association and commutation must identify one canonical join region");
		assertEquals(Set.of(aGroupId, bGroupId), invoke(originalRegion, "leafGroupIds"));
		Set<?> expandedGroupIds = (Set<?>) invoke(originalRegion, "expandedGroupIds");
		assertTrue(expandedGroupIds.contains(rootGroupId));
		assertEquals(2, expandedGroupIds.size(), "the root and nested Join groups drive region invalidation");
	}

