	@Test
	void sameNameScalarReferenceDependsOnOccurrenceVisibility() throws ReflectiveOperationException {
		Filter localFilter = new Filter(pattern("entity", "urn:test:row", "value"),
				new Exists(pattern("probe", "urn:test:flag", "flag")));
		StatementPattern laterProducer = pattern("probe", "urn:test:tag", "tag");
		Join localFirst = new Join(localFilter, laterProducer);
		Memo localMemo = memo();
		int localRootGroupId = localMemo.intern(localFirst);

		Object localExtraction = extract(localMemo, localRootGroupId,
				localMemo.group(localRootGroupId).expressions().getFirst());

		assertTrue((boolean) invoke(localExtraction, "supported"),
				"A same-name producer that occurs later cannot retroactively correlate the scalar subquery");
		JoinRegion localRegion = (JoinRegion) invoke(localExtraction, "region");
		int localFilterGroupId = localMemo.intern(localFilter.clone());
		int laterProducerGroupId = localMemo.intern(laterProducer.clone());
		int localFilterOccurrenceId = occurrenceId(localRegion, localFilterGroupId);
		int laterProducerOccurrenceId = occurrenceId(localRegion, laterProducerGroupId);
		assertEquals(Set.of(localFilterOccurrenceId), localRegion.requiredBefore(laterProducerOccurrenceId),
				"The later producer must stay after the scalar factor or it would retroactively become correlated");

		StatementPattern earlierProducer = pattern("probe", "urn:test:tag", "tag");
		Filter correlatedFilter = new Filter(pattern("entity", "urn:test:row", "value"),
				new Exists(pattern("probe", "urn:test:flag", "flag")));
		Join correlatedLater = new Join(earlierProducer, correlatedFilter);
		Memo correlatedMemo = memo();
		int correlatedRootGroupId = correlatedMemo.intern(correlatedLater);

		Object correlatedExtraction = extract(correlatedMemo, correlatedRootGroupId,
				correlatedMemo.group(correlatedRootGroupId).expressions().getFirst());

		assertFalse((boolean) invoke(correlatedExtraction, "supported"),
				"An earlier same-name producer makes the scalar reference correlated and order-sensitive");
		assertNull(invoke(correlatedExtraction, "region"));
		assertEquals("UNSUPPORTED_SEMANTIC_BARRIER", invoke(correlatedExtraction, "status").toString());
		assertTrue(boundaryReasons(correlatedExtraction).contains("CORRELATED_SCALAR_INPUT"));
	}

