	@Test
	void routeOnlyTopologiesDoNotRecursivelyExposeTheSameRegion() {
		StatementPattern a = pattern("a", "urn:test:a", "aValue");
		StatementPattern b = pattern("b", "urn:test:b", "bValue");
		Filter rewrittenFactor = new Filter(new Join(a, b), new Bound(new Var("a")));
		StatementPattern tail = pattern("b", "urn:test:tail", "tailValue");
		Join root = new Join(rewrittenFactor, tail);
		Memo memo = memo();
		int rootGroupId = memo.intern(root);
		MemoExpr rootExpression = memo.group(rootGroupId).expressions().getFirst();
		int factorGroupId = rootExpression.inputs().getFirst().groupId();
		RuleProof joinRoute = new RuleProof(JoinSearchService.ROUTE_ID, RuleKind.TRANSFORMATION,
				OptimizationGoal.BAG_SEMANTICS, Set.of("joinRegion"), "enumerated topology");

		MemoExpr routeExpression = MemoJoinSearchTestAccess.addJoinSearchAlternative(memo, factorGroupId,
				new Join(b.clone(), a.clone()), List.of(joinRoute));
		assertTrue(memo.isJoinRouteOnly(routeExpression),
				"A topology with only the unified join-search proof must remain route-only");

		List<MemoJoinRegionExtractor.Result> routeOnly = MemoJoinRegionExtractor.extractAlternatives(memo,
				rootGroupId, rootExpression, ignored -> true);
		assertEquals(List.of(2), routeOnly.stream()
				.filter(MemoJoinRegionExtractor.Result::supported)
				.map(result -> result.region().factors().size())
				.toList(),
				"A topology emitted solely by this join route must not recursively become a new outer region");

		RuleProof laterRewrite = new RuleProof("late-generic-rewrite", RuleKind.TRANSFORMATION,
				OptimizationGoal.BAG_SEMANTICS, Set.of("newLogicalShape"), "rewrite after join enumeration");
		memo.addLogicalAlternative(factorGroupId, new Join(a.clone(), b.clone()),
				List.of(joinRoute, laterRewrite)).orElseThrow();

		List<MemoJoinRegionExtractor.Result> rewritten = MemoJoinRegionExtractor.extractAlternatives(memo,
				rootGroupId, rootExpression, ignored -> true);
		assertEquals(Set.of(2, 3), rewritten.stream()
				.filter(MemoJoinRegionExtractor.Result::supported)
				.map(result -> result.region().factors().size())
				.collect(Collectors.toUnmodifiableSet()),
				"A later non-route rewrite must still reactivate surrounding join search");
	}

	@Test
	void equivalentAlternativeRegionsMergeEveryExpandedDependencyGroup() {
		StatementPattern a = pattern("seed", "urn:test:a", "seedValue");
		StatementPattern b = pattern("seed", "urn:test:b", "seedValue");
		StatementPattern c = pattern("seed", "urn:test:c", "seedValue");
		Filter rewrittenFactor = new Filter(pattern("seed", "urn:test:seed", "seedValue"),
				new Bound(new Var("seed")));
		StatementPattern tail = pattern("c", "urn:test:tail", "tailValue");
		Join root = new Join(rewrittenFactor, tail);
		Memo memo = memo();
		int rootGroupId = memo.intern(root);
		MemoExpr rootExpression = memo.group(rootGroupId).expressions().getFirst();
		int factorGroupId = rootExpression.inputs().getFirst().groupId();
		RuleProof laterRewrite = new RuleProof("late-generic-rewrite", RuleKind.TRANSFORMATION,
				OptimizationGoal.BAG_SEMANTICS, Set.of("newLogicalShape"), "rewrite after join enumeration");

		Join leftNested = new Join(a, b);
		memo.addLogicalAlternative(factorGroupId, new Join(leftNested, c), List.of(laterRewrite)).orElseThrow();
		Join rightNested = new Join(b.clone(), c.clone());
		memo.addLogicalAlternative(factorGroupId, new Join(a.clone(), rightNested), List.of(laterRewrite))
				.orElseThrow();
		int leftNestedGroupId = memo.intern(leftNested.clone());
		int rightNestedGroupId = memo.intern(rightNested.clone());

		MemoJoinRegionExtractor.Result flattened = MemoJoinRegionExtractor.extractAlternatives(memo, rootGroupId,
				rootExpression, ignored -> true)
				.stream()
				.filter(MemoJoinRegionExtractor.Result::supported)
				.filter(result -> result.region().factors().size() == 4)
				.findFirst()
				.orElseThrow();

		assertTrue(flattened.expandedGroupIds().containsAll(Set.of(leftNestedGroupId, rightNestedGroupId)),
				"Equivalent derivation routes must retain every group that can reactivate the shared region");
	}

	@Test
	void alternativeInputsExpandOnceBeforeCartesianComposition() {
		Filter leftFactor = new Filter(pattern("left", "urn:test:left-seed", "leftValue"),
				new Bound(new Var("left")));
		Filter rightFactor = new Filter(pattern("right", "urn:test:right-seed", "rightValue"),
				new Bound(new Var("right")));
		Join root = new Join(leftFactor, rightFactor);
		Memo memo = memo();
		int rootGroupId = memo.intern(root);
		MemoExpr rootExpression = memo.group(rootGroupId).expressions().getFirst();
		RuleProof laterRewrite = new RuleProof("late-generic-rewrite", RuleKind.TRANSFORMATION,
				OptimizationGoal.BAG_SEMANTICS, Set.of("newLogicalShape"), "rewrite after join enumeration");
		int leftGroupId = rootExpression.inputs().get(0).groupId();
		int rightGroupId = rootExpression.inputs().get(1).groupId();
		memo.addLogicalAlternative(leftGroupId,
				new Join(pattern("left", "urn:test:left-a", "leftValue"),
						pattern("left", "urn:test:left-b", "leftValue")),
				List.of(laterRewrite)).orElseThrow();
		memo.addLogicalAlternative(rightGroupId,
				new Join(pattern("right", "urn:test:right-a", "rightValue"),
						pattern("right", "urn:test:right-b", "rightValue")),
				List.of(laterRewrite)).orElseThrow();
		AtomicInteger admissibilityChecks = new AtomicInteger();

		MemoJoinRegionExtractor.extractAlternatives(memo, rootGroupId, rootExpression, ignored -> {
			admissibilityChecks.incrementAndGet();
			return true;
		});

		assertEquals(2, admissibilityChecks.get(),
				"Each child Join alternative should be expanded once before left/right fragments are composed");
	}

	private static Memo memo() {
		return new Memo(CascadesCostModel.from(new EvaluationStatistics()));
	}

	private static StatementPattern pattern(String predicate) {
		return new StatementPattern(new Var("s"),
				new Var("p", SimpleValueFactory.getInstance().createIRI(predicate)), new Var("o"));
	}

	private static StatementPattern pattern(String subject, String predicate, String object) {
		return new StatementPattern(new Var(subject),
				new Var("p", SimpleValueFactory.getInstance().createIRI(predicate)), new Var(object));
	}

	private static Object extract(Memo memo, int rootGroupId, MemoExpr rootExpression)
			throws ReflectiveOperationException {
		Class<?> extractor = Class.forName(
				"org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.join.MemoJoinRegionExtractor");
		Method extract = extractor.getMethod("extract", Memo.class, int.class, MemoExpr.class);
		assertTrue(Modifier.isStatic(extract.getModifiers()), "region extraction must be a pure static operation");
		return extract.invoke(null, memo, rootGroupId, rootExpression);
	}

	private static Set<String> boundaryReasons(Object extraction) throws ReflectiveOperationException {
		List<?> boundaries = (List<?>) invoke(extraction, "boundaries");
		return boundaries.stream()
				.map(boundary -> {
					try {
						return invoke(boundary, "reason").toString();
					} catch (ReflectiveOperationException e) {
						throw new AssertionError(e);
					}
				})
				.collect(Collectors.toUnmodifiableSet());
	}

	private static int occurrenceId(JoinRegion region, int groupId) {
		return region.factors()
				.stream()
				.filter(factor -> factor.groupId() == groupId)
				.mapToInt(JoinFactor::occurrenceId)
				.findFirst()
				.orElseThrow();
	}

	private static Object invoke(Object target, String methodName) throws ReflectiveOperationException {
		return target.getClass().getMethod(methodName).invoke(target);
	}
